import { useState, useEffect, useRef, useCallback } from "react";

function useScrollProgress() {
  const [progress, setProgress] = useState(0);
  const [scrollY, setScrollY] = useState(0);
  useEffect(() => {
    const handle = () => {
      const el = document.documentElement;
      const totalHeight = el.scrollHeight - el.clientHeight;
      setProgress(totalHeight > 0 ? (window.scrollY / totalHeight) * 100 : 0);
      setScrollY(window.scrollY);
    };
    window.addEventListener("scroll", handle, { passive: true });
    return () => window.removeEventListener("scroll", handle);
  }, []);
  return { progress, scrollY };
}

function useInView(threshold = 0.15) {
  const ref = useRef(null);
  const [ratio, setRatio] = useState(0);
  const [triggered, setTriggered] = useState(false);
  useEffect(() => {
    if (!ref.current) return;
    const obs = new IntersectionObserver(
      ([e]) => {
        setRatio(e.intersectionRatio);
        if (e.isIntersecting && !triggered) setTriggered(true);
      },
      { threshold: [0, 0.1, 0.2, 0.3, 0.5, 0.7, 1] }
    );
    obs.observe(ref.current);
    return () => obs.disconnect();
  }, [triggered]);
  return { ref, ratio, triggered };
}

function CinematicReveal({ children, direction = "up", delay = 0, style = {} }) {
  const { ref, triggered } = useInView(0.1);
  const transforms = {
    up: "translateY(120px)",
    left: "translateX(-120px)",
    right: "translateX(120px)",
    scale: "scale(0.7)",
  };
  return (
    <div ref={ref} style={{
        opacity: triggered ? 1 : 0,
        transform: triggered ? "translate(0,0) scale(1)" : transforms[direction],
        transition: `all 1.4s cubic-bezier(0.16, 1, 0.3, 1) ${delay}s`,
        ...style,
      }}>
      {children}
    </div>
  );
}

